// 三载体一致:产 docx 字节,零 DOM 足迹
import Docxtemplater from 'https://cdn.jsdelivr.net/npm/docxtemplater@3.69.2/+esm';
import PizZip from 'https://cdn.jsdelivr.net/npm/pizzip@3/+esm';
const zip = new PizZip(data.templateDocx);
const doc = new Docxtemplater(zip, { paragraphLoop: true, linebreaks: true });
doc.render(data.data);
const blob = doc.toBlob();
